import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { cn } from '../../../utils/cn'

// MODEL

export const TableRowState = S.Literal('selected')
export type TableRowState = typeof TableRowState.Type

export const tableRowStateValues: ReadonlyArray<TableRowState> = ['selected']

export const TableStyleOptions = S.Struct({
  className: S.optional(S.String),
  containerClassName: S.optional(S.String),
  dir: S.optional(S.String),
})
export type TableStyleOptions = typeof TableStyleOptions.Type

export const TablePartStyleOptions = S.Struct({
  className: S.optional(S.String),
})
export type TablePartStyleOptions = typeof TablePartStyleOptions.Type

export const TableRowStyleOptions = S.Struct({
  className: S.optional(S.String),
  state: S.optional(TableRowState),
})
export type TableRowStyleOptions = typeof TableRowStyleOptions.Type

type Child = Html | string

// VIEW

export type TableConfig<Message> = TableStyleOptions &
  Readonly<{
    children?: ReadonlyArray<Child>
    attributes?: ReadonlyArray<Attribute<Message>>
    containerAttributes?: ReadonlyArray<Attribute<Message>>
  }>

export type TablePartConfig<Message> = TablePartStyleOptions &
  Readonly<{
    children?: ReadonlyArray<Child>
    attributes?: ReadonlyArray<Attribute<Message>>
  }>

export type TableRowConfig<Message> = TableRowStyleOptions &
  Readonly<{
    children?: ReadonlyArray<Child>
    attributes?: ReadonlyArray<Attribute<Message>>
  }>

export const tableContainerBaseClassName = 'relative w-full overflow-x-auto'

export const tableBaseClassName = 'w-full caption-bottom text-sm'

export const tableHeaderBaseClassName = '[&_tr]:border-b'

export const tableBodyBaseClassName = '[&_tr:last-child]:border-0'

export const tableFooterBaseClassName =
  'border-t bg-muted/50 font-medium [&>tr]:last:border-b-0'

export const tableRowBaseClassName =
  'border-b transition-colors hover:bg-muted/50 has-aria-expanded:bg-muted/50 data-[state=selected]:bg-muted'

export const tableHeadBaseClassName =
  'h-10 px-2 text-left align-middle font-medium whitespace-nowrap text-foreground [&:has([role=checkbox])]:pr-0'

export const tableCellBaseClassName =
  'p-2 align-middle whitespace-nowrap [&:has([role=checkbox])]:pr-0'

export const tableCaptionBaseClassName = 'mt-4 text-sm text-muted-foreground'

export const tableContainerClassName = ({
  className,
}: TablePartStyleOptions = {}): string =>
  cn(tableContainerBaseClassName, className)

export const tableClassName = ({
  className,
}: Pick<TableStyleOptions, 'className'> = {}): string =>
  cn(tableBaseClassName, className)

export const tableHeaderClassName = ({
  className,
}: TablePartStyleOptions = {}): string =>
  cn(tableHeaderBaseClassName, className)

export const tableBodyClassName = ({
  className,
}: TablePartStyleOptions = {}): string => cn(tableBodyBaseClassName, className)

export const tableFooterClassName = ({
  className,
}: TablePartStyleOptions = {}): string =>
  cn(tableFooterBaseClassName, className)

export const tableRowClassName = ({
  className,
}: TableRowStyleOptions = {}): string => cn(tableRowBaseClassName, className)

export const tableHeadClassName = ({
  className,
}: TablePartStyleOptions = {}): string => cn(tableHeadBaseClassName, className)

export const tableCellClassName = ({
  className,
}: TablePartStyleOptions = {}): string => cn(tableCellBaseClassName, className)

export const tableCaptionClassName = ({
  className,
}: TablePartStyleOptions = {}): string =>
  cn(tableCaptionBaseClassName, className)

const slotAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  slot: string,
  className: string,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', slot),
  h.Class(className),
]

const partAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  slot: string,
  className: string,
  config: TablePartConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  ...slotAttributes(h, slot, className),
  ...(config.attributes ?? []),
]

export const Table = <Message>(config: TableConfig<Message> = {}): Html => {
  const h = html<Message>()

  return h.div(
    [
      ...slotAttributes(
        h,
        'table-container',
        tableContainerClassName({ className: config.containerClassName }),
      ),
      ...(config.containerAttributes ?? []),
    ],
    [
      h.table(
        [
          ...slotAttributes(h, 'table', tableClassName(config)),
          ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
          ...(config.attributes ?? []),
        ],
        config.children ?? [],
      ),
    ],
  )
}

export const TableHeader = <Message>(
  config: TablePartConfig<Message> = {},
): Html => {
  const h = html<Message>()

  return h.thead(
    [
      ...partAttributes(
        h,
        'table-header',
        tableHeaderClassName(config),
        config,
      ),
    ],
    config.children ?? [],
  )
}

export const TableBody = <Message>(
  config: TablePartConfig<Message> = {},
): Html => {
  const h = html<Message>()

  return h.tbody(
    [...partAttributes(h, 'table-body', tableBodyClassName(config), config)],
    config.children ?? [],
  )
}

export const TableFooter = <Message>(
  config: TablePartConfig<Message> = {},
): Html => {
  const h = html<Message>()

  return h.tfoot(
    [
      ...partAttributes(
        h,
        'table-footer',
        tableFooterClassName(config),
        config,
      ),
    ],
    config.children ?? [],
  )
}

export const TableRow = <Message>(
  config: TableRowConfig<Message> = {},
): Html => {
  const h = html<Message>()

  return h.tr(
    [
      ...slotAttributes(h, 'table-row', tableRowClassName(config)),
      ...(config.state === undefined
        ? []
        : [h.DataAttribute('state', config.state)]),
      ...(config.attributes ?? []),
    ],
    config.children ?? [],
  )
}

export const TableHead = <Message>(
  config: TablePartConfig<Message> = {},
): Html => {
  const h = html<Message>()

  return h.th(
    [...partAttributes(h, 'table-head', tableHeadClassName(config), config)],
    config.children ?? [],
  )
}

export const TableCell = <Message>(
  config: TablePartConfig<Message> = {},
): Html => {
  const h = html<Message>()

  return h.td(
    [...partAttributes(h, 'table-cell', tableCellClassName(config), config)],
    config.children ?? [],
  )
}

export const TableCaption = <Message>(
  config: TablePartConfig<Message> = {},
): Html => {
  const h = html<Message>()

  return h.caption(
    [
      ...partAttributes(
        h,
        'table-caption',
        tableCaptionClassName(config),
        config,
      ),
    ],
    config.children ?? [],
  )
}

import { Array as EffectArray, pipe } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import type { AnchorPositioningMessage } from '../../../utils/anchor-positioning'
import * as Button from '../button'
import * as DropdownMenu from '../dropdown-menu'
import {
  Table,
  TableBody,
  TableCaption,
  TableCell,
  TableFooter,
  TableHead,
  TableHeader,
  TableRow,
} from './index'

type InvoiceStatus = 'paid' | 'pending' | 'unpaid'
type PaymentMethod = 'bankTransfer' | 'creditCard' | 'paypal'
type Child = Html | string

type Invoice = Readonly<{
  invoice: string
  paymentStatus: InvoiceStatus
  totalAmount: string
  paymentMethod: PaymentMethod
}>

type InvoiceCopy = Readonly<{
  dir?: 'rtl'
  caption: string
  invoice: string
  status: string
  method: string
  amount: string
  paid: string
  pending: string
  unpaid: string
  creditCard: string
  paypal: string
  bankTransfer: string
  total: string
}>

type Product = Readonly<{
  id: string
  name: string
  price: string
}>

type ExampleDefinition = Readonly<{
  id: string
  title: string
  view: <Message = never>(controller?: TableActionsController<Message>) => Html
}>

const invoices: ReadonlyArray<Invoice> = [
  {
    invoice: 'INV001',
    paymentStatus: 'paid',
    totalAmount: '$250.00',
    paymentMethod: 'creditCard',
  },
  {
    invoice: 'INV002',
    paymentStatus: 'pending',
    totalAmount: '$150.00',
    paymentMethod: 'paypal',
  },
  {
    invoice: 'INV003',
    paymentStatus: 'unpaid',
    totalAmount: '$350.00',
    paymentMethod: 'bankTransfer',
  },
  {
    invoice: 'INV004',
    paymentStatus: 'paid',
    totalAmount: '$450.00',
    paymentMethod: 'creditCard',
  },
  {
    invoice: 'INV005',
    paymentStatus: 'paid',
    totalAmount: '$550.00',
    paymentMethod: 'paypal',
  },
  {
    invoice: 'INV006',
    paymentStatus: 'pending',
    totalAmount: '$200.00',
    paymentMethod: 'bankTransfer',
  },
  {
    invoice: 'INV007',
    paymentStatus: 'unpaid',
    totalAmount: '$300.00',
    paymentMethod: 'creditCard',
  },
]

const defaultInvoiceCopy: InvoiceCopy = {
  caption: 'A list of your recent invoices.',
  invoice: 'Invoice',
  status: 'Status',
  method: 'Method',
  amount: 'Amount',
  paid: 'Paid',
  pending: 'Pending',
  unpaid: 'Unpaid',
  creditCard: 'Credit Card',
  paypal: 'PayPal',
  bankTransfer: 'Bank Transfer',
  total: 'Total',
}

const arabicInvoiceCopy: InvoiceCopy = {
  dir: 'rtl',
  caption: 'قائمة بفواتيرك الأخيرة.',
  invoice: 'الفاتورة',
  status: 'الحالة',
  method: 'الطريقة',
  amount: 'المبلغ',
  paid: 'مدفوع',
  pending: 'قيد الانتظار',
  unpaid: 'غير مدفوع',
  creditCard: 'بطاقة ائتمانية',
  paypal: 'PayPal',
  bankTransfer: 'تحويل بنكي',
  total: 'المجموع',
}

const products: ReadonlyArray<Product> = [
  { id: 'wireless-mouse', name: 'Wireless Mouse', price: '$29.99' },
  {
    id: 'mechanical-keyboard',
    name: 'Mechanical Keyboard',
    price: '$129.99',
  },
  { id: 'usb-c-hub', name: 'USB-C Hub', price: '$49.99' },
]

const invoiceStatus = (copy: InvoiceCopy, status: InvoiceStatus): string =>
  copy[status]

const paymentMethod = (copy: InvoiceCopy, method: PaymentMethod): string =>
  copy[method]

const moreHorizontalIcon = (): Html => {
  const h = html<never>()

  return h.svg(
    [
      h.Xmlns('http://www.w3.org/2000/svg'),
      h.Width('24'),
      h.Height('24'),
      h.ViewBox('0 0 24 24'),
      h.Fill('none'),
      h.Stroke('currentColor'),
      h.StrokeWidth('2'),
      h.StrokeLinecap('round'),
      h.StrokeLinejoin('round'),
      h.Class('lucide lucide-more-horizontal'),
      h.AriaHidden(true),
    ],
    [
      h.circle([h.Cx('12'), h.Cy('12'), h.R('1')], []),
      h.circle([h.Cx('19'), h.Cy('12'), h.R('1')], []),
      h.circle([h.Cx('5'), h.Cy('12'), h.R('1')], []),
    ],
  )
}

export type TableActionsController<Message> = Readonly<{
  isOpenFor: (menuId: string, defaultOpen: boolean) => boolean
  onOpenChange: (menuId: string, change: DropdownMenu.MenuOpenChange) => Message
  onItemPress?: (menuId: string, press: DropdownMenu.MenuItemPress) => Message
  onPositioned?: (message: AnchorPositioningMessage) => Message
}>

const triggerBehaviorAttributes = <Message>(
  attributes: ReadonlyArray<Attribute<Message>>,
): ReadonlyArray<Attribute<Message>> =>
  attributes.filter(
    attribute =>
      !(attribute._tag === 'DataAttribute' && attribute.key === 'slot'),
  )

const actionButton = <Message>(
  triggerAttributes: ReadonlyArray<Attribute<Message>>,
): Html => {
  const h = html<Message>()

  return Button.view<Message>({
    variant: 'ghost',
    size: 'icon',
    className: 'size-8',
    toView: attributes =>
      h.button(
        [...attributes.button, ...triggerAttributes],
        [moreHorizontalIcon(), h.span([h.Class('sr-only')], ['Open menu'])],
      ),
  })
}

const menuItem = <Message>(
  attributes: DropdownMenu.MenuItemAttributes<Message>,
): Html => {
  const h = html<Message>()
  const children: ReadonlyArray<Child> =
    attributes.item.value === 'delete'
      ? [attributes.item.label]
      : [h.span([...attributes.label], [attributes.item.label])]

  return h.div([...attributes.root], children)
}

const optionalMenuItem = <Message>(
  attributes: DropdownMenu.MenuItemAttributes<Message> | undefined,
): ReadonlyArray<Html> =>
  attributes === undefined ? [] : [menuItem(attributes)]

const actionMenu = <Message>(
  id: string,
  controller?: TableActionsController<Message>,
): Html => {
  const h = html<Message>()
  const open = controller?.isOpenFor(id, false) ?? false
  const onItemPress = controller?.onItemPress

  return DropdownMenu.view<Message>({
    id,
    align: 'end',
    open,
    items: [
      { value: 'edit', label: 'Edit' },
      { value: 'duplicate', label: 'Duplicate' },
      { value: 'delete', label: 'Delete' },
    ],
    ...(controller === undefined
      ? {}
      : { onOpenChange: change => controller.onOpenChange(id, change) }),
    ...(onItemPress === undefined
      ? {}
      : { onItemPress: press => onItemPress(id, press) }),
    ...(controller?.onPositioned === undefined
      ? { positioning: 'static' as const }
      : { onPositioned: controller.onPositioned }),
    variant: 'destructive',
    toView: attributes =>
      h.div(
        [...attributes.root],
        [
          actionButton(triggerBehaviorAttributes(attributes.trigger)),
          h.div(
            [...attributes.portal],
            attributes.popup.isMounted
              ? [
                  h.div([...attributes.popup.backdrop.root], []),
                  h.div(
                    [...attributes.popup.positioner.root],
                    [
                      h.div(
                        [...attributes.popup.popup.root],
                        [
                          h.div(
                            [...attributes.popup.group],
                            [
                              ...optionalMenuItem(attributes.popup.items[0]),
                              ...optionalMenuItem(attributes.popup.items[1]),
                            ],
                          ),
                          h.div([...attributes.popup.separator], []),
                          h.div(
                            [...attributes.popup.group],
                            [...optionalMenuItem(attributes.popup.items[2])],
                          ),
                        ],
                      ),
                    ],
                  ),
                ]
              : [],
          ),
        ],
      ),
  })
}

const invoiceRow =
  (copy: InvoiceCopy) =>
  (invoice: Invoice): Html =>
    TableRow<never>({
      attributes: [html<never>().Key(invoice.invoice)],
      children: [
        TableCell<never>({
          className: 'font-medium',
          children: [invoice.invoice],
        }),
        TableCell<never>({
          children: [invoiceStatus(copy, invoice.paymentStatus)],
        }),
        TableCell<never>({
          children: [paymentMethod(copy, invoice.paymentMethod)],
        }),
        TableCell<never>({
          className: 'text-right',
          children: [invoice.totalAmount],
        }),
      ],
    })

const invoiceTable = (
  copy: InvoiceCopy,
  visibleInvoices: ReadonlyArray<Invoice>,
): Html =>
  Table<never>({
    dir: copy.dir,
    children: [
      TableCaption<never>({ children: [copy.caption] }),
      TableHeader<never>({
        children: [
          TableRow<never>({
            children: [
              TableHead<never>({
                className: 'w-[100px]',
                children: [copy.invoice],
              }),
              TableHead<never>({ children: [copy.status] }),
              TableHead<never>({ children: [copy.method] }),
              TableHead<never>({
                className: 'text-right',
                children: [copy.amount],
              }),
            ],
          }),
        ],
      }),
      TableBody<never>({
        children: pipe(visibleInvoices, EffectArray.map(invoiceRow(copy))),
      }),
      TableFooter<never>({
        children: [
          TableRow<never>({
            children: [
              TableCell<never>({
                attributes: [html<never>().Attribute('colspan', '3')],
                children: [copy.total],
              }),
              TableCell<never>({
                className: 'text-right',
                children: ['$2,500.00'],
              }),
            ],
          }),
        ],
      }),
    ],
  })

export const TableActions = <Message = never>(
  controller?: TableActionsController<Message>,
): Html =>
  Table<Message>({
    children: [
      TableHeader<Message>({
        children: [
          TableRow<Message>({
            children: [
              TableHead<Message>({ children: ['Product'] }),
              TableHead<Message>({ children: ['Price'] }),
              TableHead<Message>({
                className: 'text-right',
                children: ['Actions'],
              }),
            ],
          }),
        ],
      }),
      TableBody<Message>({
        children: pipe(
          products,
          EffectArray.map(product =>
            TableRow<Message>({
              attributes: [html<Message>().Key(product.id)],
              children: [
                TableCell<Message>({
                  className: 'font-medium',
                  children: [product.name],
                }),
                TableCell<Message>({ children: [product.price] }),
                TableCell<Message>({
                  className: 'text-right',
                  children: [
                    actionMenu<Message>(
                      `table-actions-${product.id}`,
                      controller,
                    ),
                  ],
                }),
              ],
            }),
          ),
        ),
      }),
    ],
  })

export const TableDemo = (): Html => invoiceTable(defaultInvoiceCopy, invoices)

export const TableFooterExample = (): Html =>
  invoiceTable(defaultInvoiceCopy, pipe(invoices, EffectArray.take(3)))

export const TableRtl = (): Html => invoiceTable(arabicInvoiceCopy, invoices)

export const tableExampleViews: ReadonlyArray<ExampleDefinition> = [
  {
    id: 'shadcn/table-actions',
    title: 'TableActions',
    view: TableActions,
  },
  {
    id: 'shadcn/table-demo',
    title: 'TableDemo',
    view: TableDemo,
  },
  {
    id: 'shadcn/table-footer',
    title: 'TableFooterExample',
    view: TableFooterExample,
  },
  {
    id: 'shadcn/table-rtl',
    title: 'TableRtl',
    view: TableRtl,
  },
]

